import json

# Get the businesses that received reviews in 2018
reviewed_businesses = var_functions.query_db:0

# Convert business_ref to business_id format
business_ids = []
for biz in reviewed_businesses:
    business_ref = biz['business_ref']
    business_id = business_ref.replace('businessref_', 'businessid_')
    business_ids.append(business_id)

# Create a MongoDB query to find these businesses and check their parking attributes
query = {
    "collection": "business",
    "filter": {
        "business_id": {"$in": business_ids},
        "$or": [
            {"attributes.BusinessParking": {"$exists": True, "$ne": None}},
            {"attributes.BikeParking": {"$exists": True, "$ne": None}}
        ]
    },
    "projection": {
        "business_id": 1,
        "attributes.BusinessParking": 1,
        "attributes.BikeParking": 1
    }
}

print("__RESULT__:")
print(json.dumps(query))

